const body = $input.first().json.body || {};
const processName = body.process_name || "Unnamed Process";
const rawText = body.raw_transcript || "";

const prompt = `
You are an expert GTM Operations Architect. Your job is to convert raw process transcripts or notes into a production-grade, standardized SOP (Standard Operating Procedure).

Process Title: ${processName}
Raw Input Data:
${rawText}

Format the output strictly in HTML containing the following structure:
<h3>1. Objective</h3>
<p>[Short, clear explanation of why this process exists.]</p>
<h3>2. Trigger Actions</h3>
<ul><li>[What event starts this SOP.]</li></ul>
<h3>3. Step-by-Step Instructions</h3>
<ol><li>[Actionable steps with clear instructions.]</li></ol>
<h3>4. Edge Cases & Exception Rules</h3>
<ul><li>[How to handle issues or deviations.]</li></ul>
<h3>5. Key Performance Indicators (KPIs)</h3>
<p>[How to measure success of this SOP.]</p>
`;

return { json: { processName, prompt } };
